    "name": "Tic Tac Toe",
    "date": "2019-07-25T13:35:58+02:00",
    "hits": 144719,
    "rating": 60,
    "thumbnail": "https://data.pacogames.com/images/230x172/tic-tac-toe-2.jpg",
